-- Supabase PostgreSQL Schema and Data Migration

CREATE TABLE master_kabupaten (
    id_kabupaten SERIAL PRIMARY KEY,
    nama_kabupaten VARCHAR(100) NOT NULL,
    kode_bps VARCHAR(10),
    koordinat_lat DECIMAL(10, 8),
    koordinat_lng DECIMAL(11, 8),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE data_alokasi_pupuk (
    id_alokasi SERIAL PRIMARY KEY,
    id_kabupaten INT REFERENCES master_kabupaten(id_kabupaten),
    musim_tanam VARCHAR(50),
    komoditas VARCHAR(100),
    luas_lahan DECIMAL(15, 2),
    kuota_urea DECIMAL(15, 2),
    kuota_npk DECIMAL(15, 2),
    prediksi_urea DECIMAL(15, 2),
    prediksi_npk DECIMAL(15, 2),
    status_risiko VARCHAR(50) DEFAULT 'Aman',
    narasi_rekomendasi TEXT,
    cuaca_anomali VARCHAR(255),
    last_analyzed_at TIMESTAMP WITH TIME ZONE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);


CREATE TABLE users (
    id_user SERIAL PRIMARY KEY,
    nip VARCHAR(18) UNIQUE NOT NULL,
    password_hash VARCHAR(255) NOT NULL,
    nama_lengkap VARCHAR(150) NOT NULL,
    role VARCHAR(50) NOT NULL,
    id_kabupaten INT REFERENCES master_kabupaten(id_kabupaten),
    last_login TIMESTAMP WITH TIME ZONE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

