INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (1, 1, 'MT I', 'Padi', 14557.00, 5408, 3557, 6760, 4446, 'Waspada', 'Berdasarkan analisis risiko La Nina, terjadi potensi pencucian hara (leaching) yang signifikan pada lahan padi seluas 14.557 Ha. Kami merekomendasikan peningkatan alokasi Urea dan NPK sebesar 25% untuk menjaga stabilitas nutrisi tanaman dan memastikan target produktivitas tetap tercapai di tengah kondisi cuaca ekstrem.', 'Cuaca Normal (Default)', '2026-06-29 08:51:54');
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (2, 1, 'MT I', 'Jagung', 26440.00, 3105, 917, 3881, 1146, 'Waspada', 'Mengingat potensi cuaca ekstrem La Nina yang meningkatkan risiko leaching hara, alokasi pupuk perlu ditingkatkan sebesar 25% untuk menjaga produktivitas jagung di Kabupaten Kepulauan Selayar. Penyesuaian ini krusial untuk mengompensasi hilangnya nutrisi akibat curah hujan tinggi dan memastikan ketersediaan hara yang cukup bagi fase pertumbuhan tanaman.', 'Cuaca Normal (Default)', '2026-06-29 08:51:56');
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (3, 2, 'MT I', 'Padi', 10594.00, 4398, 2056, 5497, 2570, 'Waspada', 'Berdasarkan potensi cuaca ekstrem La Nina, terjadi peningkatan risiko pencucian hara (leaching) yang signifikan pada lahan padi seluas 10.594 Ha. Kami merekomendasikan penambahan alokasi pupuk sebesar 25% untuk menjaga produktivitas tanaman dan mengantisipasi hilangnya efektivitas pemupukan akibat curah hujan tinggi.', 'Cuaca Normal (Default)', '2026-06-29 08:52:01');
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (4, 2, 'MT I', 'Jagung', 15987.00, 3432, 1679, 4290, 2099, 'Kritis', 'Mengingat potensi cuaca ekstrem La Nina yang memicu risiko leaching tinggi, alokasi pupuk perlu ditingkatkan sebesar 25% untuk menjaga efektivitas nutrisi tanaman jagung. Langkah ini krusial untuk mengantisipasi kehilangan hara akibat curah hujan tinggi guna memastikan produktivitas lahan seluas 15.987 hektar tetap terjaga.', 'Cuaca Normal (Default)', '2026-06-29 08:52:02');
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (5, 3, 'MT I', 'Padi', 16766.00, 3896, 1619, 4870, 2024, 'Waspada', 'Berdasarkan potensi cuaca ekstrem La Nina, risiko pencucian hara (leaching) meningkat signifikan sehingga diperlukan penambahan alokasi pupuk sebesar 25% untuk menjaga produktivitas padi. Langkah ini krusial untuk mengompensasi hilangnya nutrisi akibat curah hujan tinggi dan memastikan ketersediaan hara bagi tanaman tetap optimal.', 'Cuaca Normal (Default)', '2026-06-29 08:52:06');
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (6, 3, 'MT I', 'Jagung', 14871.00, 1921, 514, 2401, 643, 'Waspada', 'Berdasarkan potensi cuaca ekstrem La Nina, terjadi peningkatan risiko pencucian hara (leaching) yang signifikan pada lahan jagung seluas 14.871 Ha. Oleh karena itu, alokasi pupuk Urea dan NPK perlu ditingkatkan sebesar 25% dari kuota awal untuk menjaga produktivitas tanaman dan mengantisipasi hilangnya efisiensi pemupukan akibat curah hujan tinggi.', 'Cuaca Normal (Default)', '2026-06-29 08:52:08');
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (7, 4, 'MT I', 'Padi', 36627.00, 6985, 2870, 8731, 3587, 'Waspada', 'Berdasarkan potensi cuaca ekstrem La Nina, terjadi peningkatan risiko leaching yang signifikan pada lahan padi seluas 36.627 Ha di Jeneponto. Penambahan alokasi pupuk sebesar 25% direkomendasikan untuk menjaga efisiensi serapan hara tanaman dan memastikan target produktivitas tetap tercapai di tengah kondisi curah hujan tinggi.', 'Cuaca Normal (Default)', '2026-06-29 08:52:12');
