INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (38, 19, 'MT I', 'Jagung', 25671.00, 2771, 2058, 3464, 2573, 'Kritis', 'Berdasarkan analisis risiko La Nina, potensi pencucian hara (leaching) pada lahan jagung seluas 25.671 Ha meningkat signifikan. Kami merekomendasikan penambahan kuota pupuk sebesar 25% untuk menjaga produktivitas tanaman dan mengantisipasi hilangnya efektivitas pemupukan akibat curah hujan ekstrem.', 'Cuaca Normal (Default)', NULL);
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (39, 20, 'MT I', 'Padi', 10525.00, 4485, 3991, 5606, 4989, 'Waspada', 'Berdasarkan analisis risiko La Nina, terjadi potensi pencucian hara (leaching) yang signifikan pada lahan padi seluas 10.525 Ha. Oleh karena itu, alokasi pupuk Urea dan NPK perlu ditingkatkan sebesar 25% dari kuota awal untuk menjaga produktivitas tanaman dan mengantisipasi hilangnya efektivitas pemupukan akibat curah hujan tinggi.', 'Cuaca Normal (Default)', NULL);
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (40, 20, 'MT I', 'Jagung', 20702.00, 3288, 2342, 4110, 2927, 'Kritis', 'Mengingat potensi cuaca ekstrem La Nina yang memicu risiko leaching tinggi, alokasi pupuk perlu ditingkatkan sebesar 25% untuk menjaga produktivitas jagung di Luwu Timur. Penyesuaian ini krusial guna mengompensasi hilangnya unsur hara akibat curah hujan tinggi agar target hasil panen tetap tercapai.', 'Cuaca Normal (Default)', NULL);
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (41, 21, 'MT I', 'Padi', 27895.00, 2808, 1091, 3510, 1364, 'Kritis', 'Mengingat potensi cuaca ekstrem La Nina yang memicu risiko leaching tinggi, alokasi pupuk perlu ditingkatkan sebesar 25% untuk menjaga efektivitas pemupukan pada lahan seluas 27.895 Ha. Penyesuaian ini krusial untuk mencegah penurunan produktivitas padi akibat hilangnya unsur hara yang tercuci oleh curah hujan tinggi.', 'Cuaca Normal (Default)', NULL);
INSERT INTO data_alokasi_pupuk (id_alokasi, id_kabupaten, musim_tanam, komoditas, luas_lahan, kuota_urea, kuota_npk, prediksi_urea, prediksi_npk, status_risiko, narasi_rekomendasi, cuaca_anomali, last_analyzed_at) VALUES (42, 21, 'MT I', 'Jagung', 12779.00, 3720, 1626, 4650, 2032, 'Kritis', 'Mengingat potensi fenomena La Nina yang menyebabkan curah hujan ekstrem, risiko pencucian hara (leaching) pada lahan jagung di Toraja Utara meningkat signifikan. Kami merekomendasikan peningkatan alokasi pupuk sebesar 25% untuk menjaga efektivitas pemupukan dan memastikan produktivitas tanaman tetap terjaga di tengah kondisi cuaca yang tidak menentu.', 'Cuaca Normal (Default)', NULL);
